/* eslint-disable */
/**
 * Generates a self-contained, offline KaTeX bundle for the in-app WebView editor.
 *
 * Reads the installed `katex` dist (JS + CSS + woff2 fonts), inlines every font
 * as a base64 data: URI inside the CSS (so the WebView never hits the network),
 * and writes `constants/katexBundle.ts` exporting KATEX_JS + KATEX_CSS as
 * JSON-escaped string literals.
 *
 * Re-run after bumping katex:  node scripts/genKatexBundle.js
 */
const fs = require('fs');
const path = require('path');

function findKatexDist() {
  const candidates = [
    path.resolve(__dirname, '..', 'node_modules', 'katex', 'dist'),
    path.resolve(__dirname, '..', '..', 'frontend', 'node_modules', 'katex', 'dist'),
  ];
  try { candidates.unshift(path.dirname(require.resolve('katex/package.json')) + '/dist'); } catch (e) {}
  for (const c of candidates) {
    if (fs.existsSync(path.join(c, 'katex.min.js')) && fs.existsSync(path.join(c, 'katex.min.css'))) return c;
  }
  throw new Error('Could not find katex dist. Install katex (npm i katex) or run from a workspace that has it.\nLooked in:\n' + candidates.join('\n'));
}

const dist = findKatexDist();
const version = (() => {
  try { return require(path.resolve(dist, '..', 'package.json')).version; } catch (e) { return 'unknown'; }
})();

const js = fs.readFileSync(path.join(dist, 'katex.min.js'), 'utf8');
let css = fs.readFileSync(path.join(dist, 'katex.min.css'), 'utf8');

// Inline every woff2 font referenced as url(fonts/NAME.woff2) → data: URI, and
// strip the legacy woff/ttf fallbacks so the WebView never tries to fetch them.
const fontsDir = path.join(dist, 'fonts');
css = css
  // drop ",url(fonts/X.woff) format("woff")" and the ttf/truetype fallback entries
  .replace(/,url\(fonts\/[^)]+\.(?:woff|ttf)\)\s*format\("(?:woff|truetype)"\)/g, '')
  .replace(/url\(fonts\/([^)]+\.woff2)\)/g, (m, file) => {
    const p = path.join(fontsDir, file);
    const b64 = fs.readFileSync(p).toString('base64');
    return 'url(data:font/woff2;base64,' + b64 + ')';
  });

if (/url\(fonts\//.test(css)) {
  throw new Error('Some font url(fonts/...) references were left un-inlined — check the CSS format.');
}

const out = [
  '// AUTO-GENERATED by scripts/genKatexBundle.js — DO NOT EDIT.',
  '// Self-contained offline KaTeX v' + version + ' (fonts inlined as base64).',
  '// Regenerate with:  node scripts/genKatexBundle.js',
  'export const KATEX_VERSION = ' + JSON.stringify(version) + ';',
  'export const KATEX_JS = ' + JSON.stringify(js) + ';',
  'export const KATEX_CSS = ' + JSON.stringify(css) + ';',
  '',
].join('\n');

const outPath = path.resolve(__dirname, '..', 'constants', 'katexBundle.ts');
fs.mkdirSync(path.dirname(outPath), { recursive: true });
fs.writeFileSync(outPath, out);
console.log('Wrote ' + outPath);
console.log('  katex v' + version + '  |  JS ' + (js.length / 1024).toFixed(0) + ' KB  |  CSS+fonts ' + (css.length / 1024).toFixed(0) + ' KB');
